using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using McpServer;

var builder = Host.CreateApplicationBuilder(args);

builder.Services
    .AddHttpClient<WeatherApiClient>(client =>
    {
        client.BaseAddress = new Uri("https://api.open-meteo.com/");
    });

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

using System.Net.Http.Json;
using System.Text.Json.Serialization;

namespace McpServer;

/// <summary>
/// Typed HttpClient for the Open-Meteo weather API.
/// Registered via AddHttpClient&lt;T&gt; so the DI container manages
/// the underlying HttpMessageHandler lifetime automatically.
/// </summary>
public sealed class WeatherApiClient(HttpClient http)
{
    public async Task<WeatherResponse> GetCurrentWeatherAsync(
        double latitude, double longitude, CancellationToken ct = default)
    {
        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        return await http.GetFromJsonAsync<WeatherResponse>(url, ct)
            ?? throw new InvalidOperationException("Empty response from weather API");
    }
}

public sealed record WeatherResponse(
    [property: JsonPropertyName("current")] CurrentWeather Current);

public sealed record CurrentWeather(
    [property: JsonPropertyName("temperature_2m")] double Temperature,
    [property: JsonPropertyName("wind_speed_10m")] double WindSpeed);

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tool class. The SDK discovers methods marked with [McpServerTool]
/// via WithToolsFromAssembly(). Constructor parameters are resolved from DI.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools(WeatherApiClient api)
{
    [McpServerTool, Description("Get current weather for a location.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken ct)
    {
        var weather = await api.GetCurrentWeatherAsync(latitude, longitude, ct);

        return $"Temperature: {weather.Current.Temperature}°C, "
             + $"Wind: {weather.Current.WindSpeed} km/h";
    }
}

